vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = GetPixel(vUv);
ret += GetBlur1(vUv)*.2;
ret *= ret;
ret *= 2;

vec3 ret2 = mix(0,tex2d(sampler_rand00,vUv),ret.x);
ret2 = mix(ret2,tex2d(sampler_rand01,vUv),ret.y);
ret2 = mix(ret2,tex2d(sampler_rand02,vUv),ret.z);
ret = ret2;


  fragColor = ret;
}
